     1→// ============================================================================
     2→// API ROUTE: Conversations
     3→// GET: List all conversations
     4→// POST: Create new conversation
     5→// ============================================================================
     6→
     7→import { NextRequest, NextResponse } from 'next/server';
     8→import { cookies } from 'next/headers';
     9→import { prisma, isDatabaseNotInitialized } from '@/lib/db';
    10→import { logger } from '@/lib/logger';
    11→import type { Conversation, Message } from '@prisma/client';
    12→
    13→export async function GET(request: NextRequest) {
    14→  try {
    15→    const cookieStore = await cookies();
    16→    const userId = cookieStore.get('convergio-user-id')?.value;
    17→
    18→    if (!userId) {
    19→      return NextResponse.json({ error: 'No user' }, { status: 401 });
    20→    }
    21→
    22→    const { searchParams } = new URL(request.url);
    23→    const limit = parseInt(searchParams.get('limit') || '50');
    24→    const maestroId = searchParams.get('maestroId');
    25→    const activeOnly = searchParams.get('active') === 'true';
    26→
    27→    const conversations = await prisma.conversation.findMany({
    28→      where: {
    29→        userId,
    30→        ...(maestroId && { maestroId }),
    31→        ...(activeOnly && { isActive: true }),
    32→      },
    33→      orderBy: { updatedAt: 'desc' },
    34→      take: limit,
    35→      include: {
    36→        messages: {
    37→          take: 1,
    38→          orderBy: { createdAt: 'desc' },
    39→        },
    40→      },
    41→    });
    42→
    43→    return NextResponse.json(
    44→      conversations.map((c: Conversation & { messages: Message[] }) => ({
    45→        ...c,
    46→        topics: JSON.parse(c.topics || '[]'),
    47→        keyFacts: c.keyFacts ? JSON.parse(c.keyFacts) : null,
    48→        lastMessage: c.messages[0]?.content?.slice(0, 100),
    49→        messages: undefined, // Remove full messages from list
    50→      }))
    51→    );
    52→  } catch (error) {
    53→    logger.error('Conversations GET error', { error: String(error) });
    54→
    55→    if (isDatabaseNotInitialized(error)) {
    56→      return NextResponse.json(
    57→        { error: 'Database not initialized', message: 'Run: npx prisma db push' },
    58→        { status: 503 }
    59→      );
    60→    }
    61→
    62→    return NextResponse.json(
    63→      { error: 'Failed to get conversations' },
    64→      { status: 500 }
    65→    );
    66→  }
    67→}
    68→
    69→export async function POST(request: NextRequest) {
    70→  try {
    71→    const cookieStore = await cookies();
    72→    const userId = cookieStore.get('convergio-user-id')?.value;
    73→
    74→    if (!userId) {
    75→      return NextResponse.json({ error: 'No user' }, { status: 401 });
    76→    }
    77→
    78→    const data = await request.json();
    79→
    80→    if (!data.maestroId) {
    81→      return NextResponse.json(
    82→        { error: 'maestroId is required' },
    83→        { status: 400 }
    84→      );
    85→    }
    86→
    87→    const conversation = await prisma.conversation.create({
    88→      data: {
    89→        userId,
    90→        maestroId: data.maestroId,
    91→        title: data.title,
    92→      },
    93→    });
    94→
    95→    return NextResponse.json({
    96→      ...conversation,
    97→      topics: JSON.parse(conversation.topics || '[]'),
    98→    });
    99→  } catch (error) {
   100→    logger.error('Conversations POST error', { error: String(error) });
   101→    return NextResponse.json(
   102→      { error: 'Failed to create conversation' },
   103→      { status: 500 }
   104→    );
   105→  }
   106→}
