     1→/**
     2→ * ConvergioEdu Conversation Flow Component
     3→ *
     4→ * The central conversation-first interface that:
     5→ * 1. Shows character selection with photos and introductions
     6→ * 2. Routes student messages to appropriate characters
     7→ * 3. Supports seamless handoffs between characters
     8→ * 4. Offers both text and voice modes for Coach and Buddy
     9→ *
    10→ * Part of I-01: Conversation-First Main Flow
    11→ * Related: #24 MirrorBuddy Issue, #33 Conversation UX, ManifestoEdu.md
    12→ */
    13→
    14→'use client';
    15→
    16→import { useState, useRef, useEffect, useCallback, useMemo } from 'react';
    17→import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';
    18→import {
    19→  Send,
    20→  Mic,
    21→  MicOff,
    22→  Loader2,
    23→  Volume2,
    24→  VolumeX,
    25→} from 'lucide-react';
    26→import { Button } from '@/components/ui/button';
    27→import { cn } from '@/lib/utils';
    28→import { useSettingsStore } from '@/lib/stores/app-store';
    29→import { logger } from '@/lib/logger';
    30→import { useConversationFlowStore } from '@/lib/stores/conversation-flow-store';
    31→// Note: routeMessage from store is used instead of direct routeToCharacter
    32→import { analyzeHandoff } from '@/lib/ai/handoff-manager';
    33→import { useMethodProgressStore } from '@/lib/stores/method-progress-store';
    34→import type { ExtendedStudentProfile, Subject } from '@/types';
    35→// Tool integration - T-15
    36→import { ToolButtons } from './tool-buttons';
    37→import { ToolPanel } from '@/components/tools/tool-panel';
    38→import type { ToolType, ToolState } from '@/types/tools';
    39→
    40→// Map OpenAI function names to ToolType
    41→const FUNCTION_NAME_TO_TOOL_TYPE: Record<string, ToolType> = {
    42→  create_mindmap: 'mindmap',
    43→  create_quiz: 'quiz',
    44→  create_demo: 'demo',
    45→  web_search: 'search',
    46→  create_flashcards: 'flashcard',
    47→  create_diagram: 'diagram',
    48→  create_timeline: 'timeline',
    49→  create_summary: 'summary',
    50→  open_student_summary: 'summary',
    51→};
    52→// Sub-components
    53→import {
    54→  CharacterAvatar,
    55→  MessageBubble,
    56→  HandoffBanner,
    57→  ConversationHeader,
    58→  VoiceCallOverlay,
    59→  CHARACTER_AVATARS,
    60→} from './components';
    61→
    62→// Re-export CharacterCard for external use
    63→export { CharacterCard } from './components';
    64→
    65→// ============================================================================
    66→// MAIN COMPONENT
    67→// ============================================================================
    68→
    69→export function ConversationFlow() {
    70→  const [inputValue, setInputValue] = useState('');
    71→  const [isLoading, setIsLoading] = useState(false);
    72→  const [isMuted, setIsMuted] = useState(false);
    73→  const [isVoiceActive, setIsVoiceActive] = useState(false);
    74→  const [activeTool, setActiveTool] = useState<ToolState | null>(null);
    75→  const [isToolMinimized, setIsToolMinimized] = useState(false);
    76→  const [voiceSessionId, setVoiceSessionId] = useState<string | null>(null);
    77→  const messagesEndRef = useRef<HTMLDivElement>(null);
    78→  const inputRef = useRef<HTMLInputElement>(null);
    79→  const sessionStartTimeRef = useRef<number>(Date.now());
    80→  const _prefersReducedMotion = useReducedMotion(); // For future accessibility features
    81→
    82→  // Stores
    83→  const { studentProfile } = useSettingsStore();
    84→  const {
    85→    isActive,
    86→    mode,
    87→    activeCharacter,
    88→    messages,
    89→    pendingHandoff,
    90→    characterHistory,
    91→    sessionId,
    92→    startConversation,
    93→    endConversation: _endConversation, // Available for future explicit end
    94→    addMessage,
    95→    setMode,
    96→    switchToCoach,
    97→    switchToBuddy,
    98→    goBack,
    99→    acceptHandoff,
   100→    dismissHandoff,
   101→    suggestHandoff,
   102→    routeMessage,
   103→    switchToCharacter: _switchToCharacter, // Used internally via specific switch functions
   104→  } = useConversationFlowStore();
   105→
   106→  // Extended profile for routing - memoized to avoid unnecessary re-renders
   107→  const extendedProfile: ExtendedStudentProfile = useMemo(() => ({
   108→    ...studentProfile,
   109→    learningDifferences: studentProfile.learningDifferences || [],
   110→    preferredCoach: studentProfile.preferredCoach,
   111→    preferredBuddy: studentProfile.preferredBuddy,
   112→  }), [studentProfile]);
   113→
   114→  // Handle tool request from ToolButtons
   115→  const handleToolRequest = useCallback(async (toolType: ToolType) => {
   116→    if (!activeCharacter || isLoading) return;
   117→
   118→    // Create tool prompts based on type
   119→    const toolPrompts: Record<ToolType, string> = {
   120→      mindmap: 'Crea una mappa mentale su questo argomento',
   121→      quiz: 'Crea un quiz per verificare la mia comprensione',
   122→      flashcard: 'Crea delle flashcard per memorizzare',
   123→      demo: 'Crea una demo interattiva per visualizzare',
   124→      search: 'Cerca risorse educative su questo argomento',
   125→      webcam: 'Voglio scattare una foto',
   126→      diagram: 'Crea un diagramma',
   127→      timeline: 'Crea una linea del tempo',
   128→      summary: 'Crea un riassunto',
   129→      formula: 'Mostra la formula',
   130→      chart: 'Crea un grafico',
   131→      pdf: 'Analizza il PDF',
   132→      homework: 'Aiutami con i compiti',
   133→    };
   134→
   135→    const toolPrompt = toolPrompts[toolType] || `Crea ${toolType}`;
   136→    setInputValue('');
   137→    setIsLoading(true);
   138→
   139→    addMessage({ role: 'user', content: toolPrompt });
   140→
   141→    // Create initial tool state
   142→    const newTool: ToolState = {
   143→      id: `tool-${Date.now()}`,
   144→      type: toolType,
   145→      status: 'initializing',
   146→      progress: 0,
   147→      content: null,
   148→      createdAt: new Date(),
   149→    };
   150→    setActiveTool(newTool);
   151→
   152→    try {
   153→      const response = await fetch('/api/chat', {
   154→        method: 'POST',
   155→        headers: { 'Content-Type': 'application/json' },
   156→        body: JSON.stringify({
   157→          messages: [
   158→            { role: 'system', content: activeCharacter.systemPrompt },
   159→            ...messages
   160→              .filter((m) => m.role !== 'system')
   161→              .map((m) => ({ role: m.role, content: m.content })),
   162→            { role: 'user', content: toolPrompt },
   163→          ],
   164→          maestroId: activeCharacter.id,
   165→          requestedTool: toolType,
   166→        }),
   167→      });
   168→
   169→      if (!response.ok) throw new Error('Failed to get response');
   170→      const data = await response.json();
   171→
   172→      const assistantContent = data.content || data.message || '';
   173→      addMessage({ role: 'assistant', content: assistantContent });
   174→
   175→      // Update tool state based on response
   176→      if (data.toolCalls?.length > 0) {
   177→        const toolCall = data.toolCalls[0];
   178→        // Map function name (create_quiz) to tool type (quiz)
   179→        const mappedToolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || toolType;
   180→        // Extract actual data from result object
   181→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   182→        setActiveTool({
   183→          ...newTool,
   184→          type: mappedToolType,
   185→          status: 'completed',
   186→          progress: 1,
   187→          content: toolContent,
   188→        });
   189→      } else {
   190→        // No tool was created, clear the state
   191→        setActiveTool(null);
   192→      }
   193→    } catch (error) {
   194→      logger.error('Tool request error', { error });
   195→      addMessage({
   196→        role: 'assistant',
   197→        content: 'Mi dispiace, non sono riuscito a creare lo strumento. Riprova?',
   198→      });
   199→      setActiveTool({
   200→        ...newTool,
   201→        status: 'error',
   202→        error: 'Errore nella creazione dello strumento',
   203→      });
   204→    } finally {
   205→      setIsLoading(false);
   206→    }
   207→  }, [activeCharacter, isLoading, messages, addMessage]);
   208→
   209→  // Auto-scroll to bottom
   210→  useEffect(() => {
   211→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   212→  }, [messages]);
   213→
   214→  // Focus input when conversation starts
   215→  useEffect(() => {
   216→    if (isActive && mode === 'text') {
   217→      inputRef.current?.focus();
   218→    }
   219→  }, [isActive, mode]);
   220→
   221→  // Start conversation on mount if not active
   222→  useEffect(() => {
   223→    if (!isActive) {
   224→      startConversation(extendedProfile);
   225→    }
   226→  }, [isActive, startConversation, extendedProfile]);
   227→
   228→  // SSE listener for real-time tool events (Phase 4: Fullscreen Layout)
   229→  useEffect(() => {
   230→    if (!sessionId) return;
   231→
   232→    const eventSource = new EventSource(`/api/tools/sse?sessionId=${sessionId}`);
   233→
   234→    eventSource.onmessage = (event) => {
   235→      try {
   236→        const data = JSON.parse(event.data);
   237→
   238→        switch (data.type) {
   239→          case 'connected':
   240→            logger.debug('SSE connected', { sessionId, clientId: data.clientId });
   241→            break;
   242→
   243→          case 'tool:created':
   244→            // Tool creation started - show in panel
   245→            setActiveTool({
   246→              id: data.toolId,
   247→              type: data.toolType,
   248→              status: 'initializing',
   249→              progress: 0,
   250→              content: data.data,
   251→              createdAt: new Date(),
   252→            });
   253→            break;
   254→
   255→          case 'tool:update':
   256→            // Incremental update during building
   257→            setActiveTool((prev) => {
   258→              if (!prev || prev.id !== data.toolId) return prev;
   259→              return {
   260→                ...prev,
   261→                status: 'building',
   262→                progress: data.progress ?? prev.progress,
   263→                content: data.data ?? prev.content,
   264→              };
   265→            });
   266→            break;
   267→
   268→          case 'tool:complete':
   269→            // Tool finished building
   270→            setActiveTool((prev) => {
   271→              if (!prev || prev.id !== data.toolId) return prev;
   272→              return {
   273→                ...prev,
   274→                status: 'completed',
   275→                progress: 1,
   276→                content: data.data ?? prev.content,
   277→              };
   278→            });
   279→            break;
   280→
   281→          case 'tool:error':
   282→            // Tool build failed
   283→            setActiveTool((prev) => {
   284→              if (!prev || prev.id !== data.toolId) return prev;
   285→              return {
   286→                ...prev,
   287→                status: 'error',
   288→                error: data.error || 'Errore durante la creazione',
   289→              };
   290→            });
   291→            break;
   292→
   293→          case 'heartbeat':
   294→            // Keep-alive, no action needed
   295→            break;
   296→
   297→          default:
   298→            logger.debug('Unknown SSE event type', { type: data.type });
   299→        }
   300→      } catch (error) {
   301→        logger.error('SSE message parse error', { error: String(error) });
   302→      }
   303→    };
   304→
   305→    eventSource.onerror = (error) => {
   306→      logger.error('SSE connection error', { error: String(error) });
   307→      // EventSource will automatically try to reconnect
   308→    };
   309→
   310→    return () => {
   311→      eventSource.close();
   312→      logger.debug('SSE connection closed', { sessionId });
   313→    };
   314→  }, [sessionId]);
   315→
   316→  /**
   317→   * Handle sending a message.
   318→   */
   319→  const handleSend = useCallback(async () => {
   320→    if (!inputValue.trim() || isLoading || !activeCharacter) return;
   321→
   322→    const userMessage = inputValue.trim();
   323→    setInputValue('');
   324→    setIsLoading(true);
   325→
   326→    // Add user message
   327→    addMessage({ role: 'user', content: userMessage });
   328→
   329→    try {
   330→      // Route the message to determine if we need to switch characters
   331→      const routingResult = routeMessage(userMessage, extendedProfile);
   332→
   333→      // Track method progress based on intent (autonomy tracking - Issue #28)
   334→      const methodProgressStore = useMethodProgressStore.getState();
   335→
   336→      // Map main Subject type (English) to method-progress Subject type (Italian)
   337→      const mapToMethodSubject = (subject?: Subject): import('@/lib/method-progress/types').Subject | undefined => {
   338→        if (!subject) return undefined;
   339→        const subjectMap: Record<string, import('@/lib/method-progress/types').Subject> = {
   340→          mathematics: 'matematica',
   341→          physics: 'scienze',
   342→          chemistry: 'scienze',
   343→          biology: 'scienze',
   344→          history: 'storia',
   345→          geography: 'geografia',
   346→          italian: 'italiano',
   347→          english: 'inglese',
   348→          art: 'arte',
   349→          music: 'musica',
   350→        };
   351→        return subjectMap[subject] ?? 'other';
   352→      };
   353→
   354→      if (routingResult.intent.type === 'method_help' ||
   355→          routingResult.intent.type === 'emotional_support') {
   356→        // Student is seeking help - track as help request
   357→        const timeElapsed = Math.round((Date.now() - sessionStartTimeRef.current) / 1000);
   358→        methodProgressStore.recordHelpRequest(
   359→          routingResult.reason,
   360→          timeElapsed,
   361→          mapToMethodSubject(routingResult.intent.subject)
   362→        );
   363→      } else if (routingResult.intent.type === 'academic_help' &&
   364→                 activeCharacter?.type === 'maestro') {
   365→        // Student is working independently with a maestro
   366→        // Only track as "solved alone" if they've been working for a while
   367→        if (messages.length > 4) {
   368→          methodProgressStore.recordProblemSolvedAlone(
   369→            userMessage.slice(0, 100),
   370→            mapToMethodSubject(routingResult.intent.subject)
   371→          );
   372→        }
   373→      }
   374→
   375→      // Check if we should suggest a handoff
   376→      if (
   377→        routingResult.characterType !== activeCharacter.type &&
   378→        routingResult.intent.confidence >= 0.7
   379→      ) {
   380→        // High confidence different character needed - suggest handoff
   381→        const { getMaestroById: _getMaestroById } = await import('@/data/maestri');
   382→        const { getSupportTeacherById } = await import('@/data/support-teachers');
   383→        const { getBuddyById } = await import('@/data/buddy-profiles');
   384→
   385→        let targetCharacter;
   386→        switch (routingResult.characterType) {
   387→          case 'maestro':
   388→            targetCharacter = routingResult.character;
   389→            break;
   390→          case 'coach':
   391→            targetCharacter =
   392→              getSupportTeacherById(extendedProfile.preferredCoach || 'melissa') ||
   393→              routingResult.character;
   394→            break;
   395→          case 'buddy':
   396→            targetCharacter =
   397→              getBuddyById(extendedProfile.preferredBuddy || 'mario') ||
   398→              routingResult.character;
   399→            break;
   400→        }
   401→
   402→        if (targetCharacter && targetCharacter.id !== activeCharacter.id) {
   403→          // Create active character for handoff
   404→          const handoffCharacter = {
   405→            type: routingResult.characterType,
   406→            id: targetCharacter.id,
   407→            name: targetCharacter.name,
   408→            character: targetCharacter,
   409→            greeting:
   410→              routingResult.characterType === 'buddy' && 'getGreeting' in targetCharacter
   411→                ? (targetCharacter as { getGreeting: (p: ExtendedStudentProfile) => string }).getGreeting(extendedProfile)
   412→                : 'greeting' in targetCharacter ? String(targetCharacter.greeting) : '',
   413→            systemPrompt:
   414→              routingResult.characterType === 'buddy' && 'getSystemPrompt' in targetCharacter
   415→                ? (targetCharacter as { getSystemPrompt: (p: ExtendedStudentProfile) => string }).getSystemPrompt(extendedProfile)
   416→                : 'systemPrompt' in targetCharacter ? String(targetCharacter.systemPrompt) : '',
   417→            color: targetCharacter.color,
   418→            voice: 'voice' in targetCharacter ? targetCharacter.voice : 'alloy',
   419→            voiceInstructions: 'voiceInstructions' in targetCharacter ? targetCharacter.voiceInstructions : '',
   420→          };
   421→
   422→          // Suggest handoff instead of auto-switching
   423→          suggestHandoff({
   424→            toCharacter: handoffCharacter,
   425→            reason: routingResult.reason,
   426→            confidence: routingResult.intent.confidence,
   427→          });
   428→        }
   429→      }
   430→
   431→      // Send to AI for response (simulated for now - will integrate with chat API)
   432→      const response = await fetch('/api/chat', {
   433→        method: 'POST',
   434→        headers: { 'Content-Type': 'application/json' },
   435→        body: JSON.stringify({
   436→          messages: [
   437→            { role: 'system', content: activeCharacter.systemPrompt },
   438→            ...messages
   439→              .filter((m) => m.role !== 'system')
   440→              .map((m) => ({
   441→                role: m.role,
   442→                content: m.content,
   443→              })),
   444→            { role: 'user', content: userMessage },
   445→          ],
   446→          maestroId: activeCharacter.id,
   447→        }),
   448→      });
   449→
   450→      if (!response.ok) {
   451→        throw new Error('Failed to get response');
   452→      }
   453→
   454→      const data = await response.json();
   455→      const assistantContent = data.content || data.message || '';
   456→      addMessage({ role: 'assistant', content: assistantContent });
   457→
   458→      // Also check AI response for handoff signals (reactive detection)
   459→      if (!pendingHandoff) {
   460→        const handoffAnalysis = analyzeHandoff({
   461→          message: userMessage,
   462→          aiResponse: assistantContent,
   463→          activeCharacter,
   464→          studentProfile: extendedProfile,
   465→          recentMessages: messages.slice(-5).map((m) => ({
   466→            role: m.role === 'system' ? 'assistant' : (m.role as 'user' | 'assistant'),
   467→            content: m.content,
   468→          })),
   469→        });
   470→
   471→        if (handoffAnalysis.shouldHandoff && handoffAnalysis.suggestion && handoffAnalysis.confidence > 0.7) {
   472→          suggestHandoff(handoffAnalysis.suggestion);
   473→        }
   474→      }
   475→    } catch (error) {
   476→      logger.error('Chat error', { error });
   477→      addMessage({
   478→        role: 'assistant',
   479→        content: 'Mi dispiace, ho avuto un problema. Puoi riprovare?',
   480→      });
   481→    } finally {
   482→      setIsLoading(false);
   483→    }
   484→  }, [
   485→    inputValue,
   486→    isLoading,
   487→    activeCharacter,
   488→    addMessage,
   489→    messages,
   490→    extendedProfile,
   491→    routeMessage,
   492→    suggestHandoff,
   493→    pendingHandoff,
   494→  ]);
   495→
   496→  /**
   497→   * Handle key press in input.
   498→   */
   499→  const handleKeyPress = (e: React.KeyboardEvent) => {
   500→    if (e.key === 'Enter' && !e.shiftKey) {
   501→      e.preventDefault();
   502→      handleSend();
   503→    }
   504→  };
   505→
   506→  /**
   507→   * Handle voice mode toggle (for input area).
   508→   */
   509→  const handleVoiceToggle = () => {
   510→    if (mode === 'voice') {
   511→      setMode('text');
   512→    } else {
   513→      setMode('voice');
   514→    }
   515→  };
   516→
   517→  /**
   518→   * Handle voice call (full voice conversation).
   519→   */
   520→  const handleVoiceCall = useCallback(() => {
   521→    if (isVoiceActive) {
   522→      // End voice call
   523→      setIsVoiceActive(false);
   524→      setMode('text');
   525→    } else {
   526→      // Start voice call
   527→      setIsVoiceActive(true);
   528→      setMode('voice');
   529→      // Voice session will be started by VoiceCallOverlay
   530→      // This is a placeholder - Issue #34 tracks voice WebSocket issues
   531→    }
   532→  }, [isVoiceActive, setMode]);
   533→
   534→  /**
   535→   * Handle accepting handoff.
   536→   */
   537→  const handleAcceptHandoff = () => {
   538→    acceptHandoff(extendedProfile);
   539→  };
   540→
   541→  /**
   542→   * Handle manual character switches.
   543→   */
   544→  const handleSwitchToCoach = () => switchToCoach(extendedProfile);
   545→  const handleSwitchToBuddy = () => switchToBuddy(extendedProfile);
   546→  const handleGoBack = () => goBack(extendedProfile);
   547→
   548→  // Render idle state (shouldn't happen with auto-start)
   549→  if (!isActive || !activeCharacter) {
   550→    return (
   551→      <div className="flex items-center justify-center h-full">
   552→        <Button onClick={() => startConversation(extendedProfile)}>
   553→          Inizia una conversazione
   554→        </Button>
   555→      </div>
   556→    );
   557→  }
   558→
   559→  // Video conference layout when tool is active (Issue #36)
   560→  const hasActiveTool = activeTool && activeTool.status !== 'error';
   561→
   562→  return (
   563→    <div className="relative flex flex-col h-[calc(100vh-200px)] max-h-[700px] bg-white dark:bg-slate-900 rounded-2xl shadow-xl overflow-hidden">
   564→      {/* Voice call overlay */}
   565→      <AnimatePresence>
   566→        {isVoiceActive && activeCharacter && (
   567→          <VoiceCallOverlay
   568→            character={activeCharacter}
   569→            onEnd={handleVoiceCall}
   570→            onSessionIdChange={setVoiceSessionId}
   571→          />
   572→        )}
   573→      </AnimatePresence>
   574→
   575→      {/* Header with character info and voice call button - 10% */}
   576→      <ConversationHeader
   577→        currentCharacter={activeCharacter}
   578→        onSwitchToCoach={handleSwitchToCoach}
   579→        onSwitchToBuddy={handleSwitchToBuddy}
   580→        onGoBack={handleGoBack}
   581→        canGoBack={characterHistory.length > 1}
   582→        isVoiceActive={isVoiceActive}
   583→        onVoiceCall={handleVoiceCall}
   584→      />
   585→
   586→      {/* Handoff suggestion */}
   587→      <AnimatePresence>
   588→        {pendingHandoff && (
   589→          <HandoffBanner
   590→            suggestion={pendingHandoff}
   591→            onAccept={handleAcceptHandoff}
   592→            onDismiss={dismissHandoff}
   593→          />
   594→        )}
   595→      </AnimatePresence>
   596→
   597→      {/* Main content area - switches between chat-first and tool-first layouts */}
   598→      {hasActiveTool ? (
   599→        /* VIDEO CONFERENCE LAYOUT: Tool takes center stage (Issue #36) */
   600→        <div className="flex-1 flex flex-col overflow-hidden">
   601→          {/* Tool panel - 70% of remaining space */}
   602→          <div className="flex-[7] overflow-auto border-b border-slate-200 dark:border-slate-700">
   603→            <ToolPanel
   604→              tool={activeTool}
   605→              maestro={activeCharacter ? {
   606→                name: activeCharacter.name,
   607→                avatar: CHARACTER_AVATARS[activeCharacter.id] || '/avatars/default.jpg',
   608→                color: activeCharacter.color,
   609→              } : null}
   610→              onClose={() => setActiveTool(null)}
   611→              isMinimized={isToolMinimized}
   612→              onToggleMinimize={() => setIsToolMinimized(!isToolMinimized)}
   613→              embedded={true}
   614→              sessionId={voiceSessionId}
   615→            />
   616→          </div>
   617→
   618→          {/* Mini chat - 15% of remaining space */}
   619→          <div
   620→            className="flex-[1.5] overflow-y-auto p-2 bg-slate-50 dark:bg-slate-800/50"
   621→            role="log"
   622→            aria-live="polite"
   623→            aria-label="Messaggi recenti"
   624→          >
   625→            {/* Show only last 3 messages in mini view */}
   626→            {messages.slice(-3).map((message) => (
   627→              <div
   628→                key={message.id}
   629→                className={cn(
   630→                  'text-xs py-1 px-2 rounded mb-1',
   631→                  message.role === 'user'
   632→                    ? 'bg-accent-themed/10 text-right'
   633→                    : 'bg-slate-200 dark:bg-slate-700'
   634→                )}
   635→              >
   636→                <span className="font-medium">
   637→                  {message.role === 'user' ? 'Tu' : activeCharacter?.name}:
   638→                </span>{' '}
   639→                {message.content.substring(0, 80)}
   640→                {message.content.length > 80 && '...'}
   641→              </div>
   642→            ))}
   643→            {isLoading && (
   644→              <div className="text-xs py-1 px-2 flex items-center gap-1">
   645→                <Loader2 className="w-3 h-3 animate-spin" />
   646→                <span>{activeCharacter?.name} sta pensando...</span>
   647→              </div>
   648→            )}
   649→          </div>
   650→        </div>
   651→      ) : (
   652→        /* NORMAL LAYOUT: Chat takes full space */
   653→        <div
   654→          className="flex-1 overflow-y-auto p-4"
   655→          role="log"
   656→          aria-live="polite"
   657→          aria-label="Messaggi della conversazione"
   658→        >
   659→          {messages.map((message) => (
   660→            <MessageBubble
   661→              key={message.id}
   662→              message={message}
   663→              activeCharacter={
   664→                message.role === 'assistant' ? activeCharacter : null
   665→              }
   666→            />
   667→          ))}
   668→          {isLoading && (
   669→            <motion.div
   670→              initial={{ opacity: 0 }}
   671→              animate={{ opacity: 1 }}
   672→              className="flex gap-3 mb-4"
   673→            >
   674→              <CharacterAvatar character={activeCharacter} size="sm" />
   675→              <div className="px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-md">
   676→                <Loader2 className="w-5 h-5 animate-spin text-slate-500" />
   677→              </div>
   678→            </motion.div>
   679→          )}
   680→          <div ref={messagesEndRef} />
   681→        </div>
   682→      )}
   683→
   684→      {/* Input area - 5% */}
   685→      <div className="p-4 border-t border-slate-200 dark:border-slate-700">
   686→        <div className="flex items-center gap-2">
   687→          {/* Tool buttons - quick access to educational tools */}
   688→          <ToolButtons
   689→            onToolRequest={handleToolRequest}
   690→            disabled={isLoading}
   691→            activeToolId={activeTool?.id}
   692→          />
   693→          <input
   694→            ref={inputRef}
   695→            type="text"
   696→            value={inputValue}
   697→            onChange={(e) => setInputValue(e.target.value)}
   698→            onKeyDown={handleKeyPress}
   699→            placeholder={`Scrivi a ${activeCharacter.name}...`}
   700→            aria-label={`Scrivi un messaggio a ${activeCharacter.name}`}
   701→            className="flex-1 px-4 py-3 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 focus:ring-accent-themed outline-none text-slate-900 dark:text-white placeholder:text-slate-500"
   702→            disabled={isLoading}
   703→          />
   704→          <Button
   705→            variant="ghost"
   706→            size="icon"
   707→            onClick={() => setIsMuted(!isMuted)}
   708→            aria-label={isMuted ? 'Attiva audio' : 'Disattiva audio'}
   709→            aria-pressed={isMuted}
   710→          >
   711→            {isMuted ? (
   712→              <VolumeX className="w-5 h-5" />
   713→            ) : (
   714→              <Volume2 className="w-5 h-5" />
   715→            )}
   716→          </Button>
   717→          <Button
   718→            variant="ghost"
   719→            size="icon"
   720→            onClick={handleVoiceToggle}
   721→            aria-label={mode === 'voice' ? 'Passa al testo' : 'Passa alla voce'}
   722→            aria-pressed={mode === 'voice'}
   723→            className={cn(mode === 'voice' && 'bg-red-100 text-red-600')}
   724→          >
   725→            {mode === 'voice' ? (
   726→              <MicOff className="w-5 h-5" />
   727→            ) : (
   728→              <Mic className="w-5 h-5" />
   729→            )}
   730→          </Button>
   731→          <Button
   732→            size="icon"
   733→            onClick={handleSend}
   734→            disabled={!inputValue.trim() || isLoading}
   735→            aria-label="Invia messaggio"
   736→            className="bg-accent-themed hover:bg-accent-themed/90"
   737→          >
   738→            <Send className="w-5 h-5" aria-hidden="true" />
   739→          </Button>
   740→        </div>
   741→      </div>
   742→    </div>
   743→  );
   744→}
